def _configure_cmake(self):
        cmake = CMake(self)
        cmake.definitions["CMAKE_INSTALL_CMAKEDIR"] = self._cmake_install_base_path.replace("\\", "/")
        cmake.definitions["protobuf_WITH_ZLIB"] = self.options.with_zlib
        cmake.definitions["protobuf_BUILD_TESTS"] = False
        cmake.definitions["protobuf_BUILD_PROTOC_BINARIES"] = True
        if not self.options.debug_suffix:
            cmake.definitions["protobuf_DEBUG_POSTFIX"] = ""
        if Version(self.version) >= "3.14.0":
            cmake.definitions["protobuf_BUILD_LIBPROTOC"] = True
        if self._can_disable_rtti:
            cmake.definitions["protobuf_DISABLE_RTTI"] = not self.options.with_rtti
        if is_msvc(self) or self._is_clang_cl:
            runtime = msvc_runtime_flag(self)
            if not runtime:
                runtime = self.settings.get_safe("compiler.runtime")
            cmake.definitions["protobuf_MSVC_STATIC_RUNTIME"] = "MT" in runtime
        if Version(self.version) < "3.18.0" and self._is_clang_cl:
            cmake.definitions["CMAKE_RC_COMPILER"] = os.environ.get("RC", "llvm-rc")
        cmake.configure(build_folder=self._build_subfolder)
        return cmake

gpt_code:
def _configure_cmake(self):
    cmake = CMake(self)

    # Build the base cmake definitions
    definitions = {
        "CMAKE_INSTALL_CMAKEDIR": self._cmake_install_base_path.replace("\\", "/"),
        "protobuf_WITH_ZLIB": self.options.with_zlib,
        "protobuf_BUILD_TESTS": False,
        "protobuf_BUILD_PROTOC_BINARIES": True
    }

    # Conditionally add other cmake definitions
    conditional_defs = {}

    if not self.options.debug_suffix:
        conditional_defs["protobuf_DEBUG_POSTFIX"] = ""

    if Version(self.version) >= "3.14.0":
        conditional_defs["protobuf_BUILD_LIBPROTOC"] = True

    if self._can_disable_rtti:
        conditional_defs["protobuf_DISABLE_RTTI"] = not self.options.with_rtti

    if is_msvc(self) or self._is_clang_cl:
        runtime = msvc_runtime_flag(self) or self.settings.get_safe("compiler.runtime")
        conditional_defs["protobuf_MSVC_STATIC_RUNTIME"] = "MT" in runtime

    if Version(self.version) < "3.18.0" and self._is_clang_cl:
        conditional_defs["CMAKE_RC_COMPILER"] = os.environ.get("RC", "llvm-rc")

    # Combine fixed and conditional definitions using dictionary unpacking
    cmake.definitions = {**definitions, **conditional_defs}

    cmake.configure(build_folder=self._build_subfolder)

    return cmake

