def create_user(self, user, password):
    # Create the user's account on RocketChat
    if not self.rocket:
        return
    email = user.email or f"{user.uuid}@rocketchat.com"
    user_data = {
        'email': email,
        'name': user.name,
        'password': password,
        'username': user.handle.replace(" ", "_")
    }
    account = self.rocket.users_create(*user_data.values()).json()
    self.create_team(user.team, account)

