def _load_choices(tokens):
    choices = defaultdict(dict)

    for choice in tokens.get('VAL_', []):
        if len(choice[1]) == 0:
            continue

        od = odict((int(v[0]), NamedSignalValue(v[0], v[1])) for v in choice[3])

        if len(od) == 0:
            continue

        frame_id = int(choice[1][0])
        choices[frame_id][choice[2]] = od

    return choices

gpt_code:
from collections import defaultdict, OrderedDict as odict

def _load_choices(tokens):
    choices = defaultdict(dict)

    for choice in tokens.get('VAL_', []):
        if not choice[1]:
            continue

        od = odict({int(v[0]): NamedSignalValue(v[0], v[1]) for v in choice[3]})

        if not od:
            continue

        frame_id = int(choice[1][0])
        choices[frame_id] = {**choices[frame_id], choice[2]: od}

    return choices

