def updateBackground(self):
    img = ""
    if settings.corkBackground["image"]:
        img = findBackground(settings.corkBackground["image"]) or ""

    self.setStyleSheet("""QListView {{
        background:{color};
        background-image: url({url});
        background-attachment: fixed;
